// Notion v2.2: Properties als property_feldname
// Termine aufteilen in NEU und ABGELAUFEN, dann x Kunden flatten
var items = $input.all();
var flat = [];
var now = new Date();
var cutoff = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

for (var i = 0; i < items.length; i++) {
  var props = items[i].json;
  var notionPageId = props.id;

  // Datum (Date-Feld mit Uhrzeit)
  var datumObj = props.property_datum;
  var datumRaw = null;
  if (datumObj && datumObj.start) {
    datumRaw = datumObj.start;
  } else if (typeof datumObj === 'string' && datumObj.length >= 10) {
    datumRaw = datumObj;
  }
  if (!datumRaw) continue;

  var terminDate = new Date(datumRaw);

  // ConfluenceSync Checkbox
  var confluenceSync = props.property_confluence_sync === true
    || props.property_confluencesync === true;

  // Typ bestimmen
  var typ = null;
  if (!confluenceSync && terminDate >= cutoff) {
    typ = 'NEU';
  } else if (confluenceSync && terminDate < cutoff) {
    typ = 'ABGELAUFEN';
  }
  if (!typ) continue;

  // Felder lesen
  var titel = props.property_titel || props.name || 'Kein Titel';
  var ort = props.property_ort || '';

  // Datum aus ISO-String parsen (kein Timezone-Problem)
  var datumIso = datumRaw.substring(0, 10);
  var dp = datumIso.split('-');
  var datumStr = dp[2] + '.' + dp[1] + '.' + dp[0];

  // Uhrzeit aus ISO-String
  var uhrzeitStr = '';
  var tIdx = datumRaw.indexOf('T');
  if (tIdx !== -1) {
    uhrzeitStr = datumRaw.substring(tIdx + 1, tIdx + 6);
  }

  // Kunden Relation (Array von Notion Page IDs)
  var kundenRaw = props.property_kunden || [];
  var kundenIds = Array.isArray(kundenRaw) ? kundenRaw : [kundenRaw];
  if (kundenIds.length === 0) continue;

  // ConfluenceTerminIDs (Umlaut-Normalisierung: TerminIDs -> termin_i_ds)
  var confluenceTerminIDs = props.property_confluence_termin_i_ds
    || props.property_confluenceterminids
    || props.property_confluence_termin_ids
    || '';

  // Row ID = notionPageId ohne Bindestriche
  var rowId = notionPageId.replace(/-/g, '');

  for (var j = 0; j < kundenIds.length; j++) {
    var kundePageId = kundenIds[j];
    if (!kundePageId) continue;
    flat.push({
      json: {
        notionPageId: notionPageId,
        titel: titel,
        ort: ort,
        datumStr: datumStr,
        uhrzeitStr: uhrzeitStr,
        datumIso: datumIso,
        kundePageId: kundePageId,
        confluenceTerminIDs: confluenceTerminIDs,
        rowId: rowId,
        typ: typ
      }
    });
  }
}

return flat;

// Neue Zeile gezielt im Panel 'Naechste Termine' einfuegen
var page = $json;
var d = $('Set: Daten zusammenfuehren').item.json;

var esc = function(s) {
  return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
};

var rowId = d.rowId;
var spaceKey = d.spaceKey;
var terminRowId = rowId + '-' + spaceKey;
var datumIso = d.datumIso;
var datumStr = d.datumStr;
var uhrzeitStr = d.uhrzeitStr || '';
var titel = esc(d.titel);
var ort = esc(d.ort);

var pageId = page.id || '';
var pageTitle = page.title || '';
var currentVersion = (page.version && page.version.number) ? page.version.number : 1;
var html = (page.body && page.body.storage && page.body.storage.value)
  ? page.body.storage.value : '';

var marker = '<!--tid:' + terminRowId + ' dt:' + datumIso + '-->';
var newRowContent = marker + '<td>' + datumStr + '</td><td>' + uhrzeitStr + '</td><td>' + titel + '</td><td>' + ort + '</td></tr>';

// 'Naechste Termine' Panel exakt lokalisieren – verschiedene HTML-Encodings probieren
var panelTitles = ['N\u00e4chste Termine', 'N&auml;chste Termine', 'N&#228;chste Termine', 'Naechste Termine'];
var titleIdx = -1;
var panelTitle = '';
for (var pi = 0; pi < panelTitles.length; pi++) {
  titleIdx = html.indexOf(panelTitles[pi]);
  if (titleIdx !== -1) { panelTitle = panelTitles[pi]; break; }
}

// <ac:rich-text-body> des Panels finden – der Abschnitt der NACH dem Titel-Tag kommt
var rtbOpen = '<ac:rich-text-body>';
var rtbClose = '</ac:rich-text-body>';
var bodyStart = -1;
var bodyEnd = -1;

if (titleIdx !== -1) {
  var searchFrom = titleIdx + panelTitle.length;
  var rtbStartIdx = html.indexOf(rtbOpen, searchFrom);
  if (rtbStartIdx !== -1) {
    bodyStart = rtbStartIdx + rtbOpen.length;
    bodyEnd = html.indexOf(rtbClose, bodyStart);
  }
}

if (bodyStart === -1 || bodyEnd === -1) {
  // Fallback: Panel nicht gefunden – Fehlerinfo ausgeben, kein Schreiben
  throw new Error('Panel Naechste Termine nicht gefunden. pageId: ' + pageId);
}

var bodyContent = html.substring(bodyStart, bodyEnd);

if (bodyContent.indexOf('<tr>') === -1) {
  // Panel hat noch keine Datenzeilen (oder nur Platzhalter-Zeilen ohne Marker)
  // Tabelle komplett neu aufbauen und bisherigen Inhalt ersetzen
  bodyContent = '<table><tbody><tr><th>Datum</th><th>Uhrzeit</th><th>Titel</th><th>Ort</th></tr><tr>' + newRowContent + '</tbody></table>';
} else {
  // Zeilen aufteilen, neue Zeile hinzufuegen, nach ISO-Datum sortieren
  // split('<tr>') liefert: [0]=vor-erster-tr, [1]=header-zeile-inhalt, [2..n]=datenzeilen
  var parts = bodyContent.split('<tr>');
  var headerPart = parts[0];
  var headerRow = parts.length > 1 ? parts[1] : '<th>Datum</th><th>Uhrzeit</th><th>Titel</th><th>Ort</th></tr>';
  var dataRows = parts.slice(2);

  dataRows.push(newRowContent);

  dataRows.sort(function(a, b) {
    var getDate = function(row) {
      var m = row.match(/<!--tid:\S+ dt:(\d{4}-\d{2}-\d{2})-->/);
      return m ? new Date(m[1]).getTime() : 0;
    };
    return getDate(a) - getDate(b);
  });

  bodyContent = headerPart + '<tr>' + headerRow + dataRows.map(function(r) { return '<tr>' + r; }).join('');
}

// Nur den Panel-Inhalt ersetzen, Rest der Seite unveraendert lassen
html = html.substring(0, bodyStart) + bodyContent + html.substring(bodyEnd);

var prev = d.confluenceTerminIDs || '';
var newEntry = spaceKey + ':' + terminRowId;
var updatedTerminIDs = prev ? prev + ',' + newEntry : newEntry;

return {
  json: {
    pageId: pageId,
    pageTitle: pageTitle,
    newVersion: currentVersion + 1,
    updatedHtml: html,
    notionPageId: d.notionPageId,
    updatedTerminIDs: updatedTerminIDs
  }
};

// Zeile gezielt im Panel 'Naechste Termine' loeschen
var page = $json;
var d = $('Set: Daten zusammenfuehren').item.json;

var spaceKey = d.spaceKey;
var rowId = d.rowId;
var terminRowId = rowId + '-' + spaceKey;

// Gespeicherte Row ID fuer diesen Space Key aus ConfluenceTerminIDs lesen
var confIDs = d.confluenceTerminIDs || '';
var storedRowId = terminRowId;
var entries = confIDs.split(',').map(function(e) { return e.trim(); }).filter(function(e) { return e.indexOf(':') !== -1; });
for (var k = 0; k < entries.length; k++) {
  if (entries[k].indexOf(spaceKey + ':') === 0) {
    storedRowId = entries[k].substring(spaceKey.length + 1);
    break;
  }
}

var pageId = page.id || '';
var pageTitle = page.title || '';
var currentVersion = (page.version && page.version.number) ? page.version.number : 1;
var html = (page.body && page.body.storage && page.body.storage.value)
  ? page.body.storage.value : '';

// 'Naechste Termine' Panel exakt lokalisieren
var panelTitles = ['N\u00e4chste Termine', 'N&auml;chste Termine', 'N&#228;chste Termine', 'Naechste Termine'];
var titleIdx = -1;
var panelTitle = '';
for (var pi = 0; pi < panelTitles.length; pi++) {
  titleIdx = html.indexOf(panelTitles[pi]);
  if (titleIdx !== -1) { panelTitle = panelTitles[pi]; break; }
}

var rtbOpen = '<ac:rich-text-body>';
var rtbClose = '</ac:rich-text-body>';
var bodyStart = -1;
var bodyEnd = -1;

if (titleIdx !== -1) {
  var searchFrom = titleIdx + panelTitle.length;
  var rtbStartIdx = html.indexOf(rtbOpen, searchFrom);
  if (rtbStartIdx !== -1) {
    bodyStart = rtbStartIdx + rtbOpen.length;
    bodyEnd = html.indexOf(rtbClose, bodyStart);
  }
}

var markerPattern = '<!--tid:' + storedRowId + ' ';

if (bodyStart !== -1 && bodyEnd !== -1) {
  // Nur innerhalb des Panels loeschen
  var bodyContent = html.substring(bodyStart, bodyEnd);
  var parts = bodyContent.split('<tr>');
  var filtered = parts.filter(function(p) { return p.indexOf(markerPattern) === -1; });
  bodyContent = filtered.join('<tr>');
  html = html.substring(0, bodyStart) + bodyContent + html.substring(bodyEnd);
} else {
  // Fallback: gesamte Seite (sollte nicht vorkommen)
  var parts2 = html.split('<tr>');
  var filtered2 = parts2.filter(function(p) { return p.indexOf(markerPattern) === -1; });
  html = filtered2.join('<tr>');
}

return {
  json: {
    pageId: pageId,
    pageTitle: pageTitle,
    newVersion: currentVersion + 1,
    updatedHtml: html,
    notionPageId: d.notionPageId
  }
};
